from pathlib import Path

import pytest

from agentpulse.db import close_db, init_db
from agentpulse.platforms.claude import schema
from agentpulse.ui import costs


@pytest.fixture
async def db(tmp_path: Path):
    conn = await init_db(db_path=tmp_path / "test.db")
    yield conn
    await close_db()


# 2026-04-21 22:27:43 UTC == 1777152463 — picking timestamps that fall on
# distinct local dates to keep the day buckets predictable across timezones.
DAY1_START = 1777152463.0
DAY2_START = DAY1_START + 86400.0
DAY3_START = DAY1_START + 2 * 86400.0


async def _seed_statusline(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    cost_usd: float,
    cwd: str = "/proj",
    source_system: str = "host",
    input_tokens: int | None = None,
    output_tokens: int | None = None,
    cache_read_tokens: int | None = None,
    cache_creation_tokens: int | None = None,
) -> None:
    ctx: dict = {}
    if input_tokens is not None:
        ctx["total_input_tokens"] = input_tokens
    if output_tokens is not None:
        ctx["total_output_tokens"] = output_tokens
    if cache_read_tokens is not None or cache_creation_tokens is not None:
        usage: dict = {}
        if cache_read_tokens is not None:
            usage["cache_read_input_tokens"] = cache_read_tokens
        if cache_creation_tokens is not None:
            usage["cache_creation_input_tokens"] = cache_creation_tokens
        ctx["current_usage"] = usage
    payload = {
        "session_id": session_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
        "cost": {"total_cost_usd": cost_usd},
        "context_window": ctx,
    }
    await schema.insert_log_statusline(
        db, payload=payload, received_at=received_at, received_by="test"
    )
    await db.commit()


async def _seed_death(
    db,
    *,
    pid: int,
    observed_at: float,
    cwd: str = "/proj",
    source_system: str = "host",
) -> None:
    await schema.insert_log_pid_death(
        db,
        pid=pid,
        source_system=source_system,
        cwd=cwd,
        observed_at=observed_at,
        observed_by="pid-watcher",
    )
    await db.commit()


class TestCostsByDay:
    async def test_empty_db_returns_empty_list(self, db) -> None:
        result = await costs.costs_by_day(db)
        assert result == []

    async def test_single_process_one_day(self, db) -> None:
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=2.5
        )
        result = await costs.costs_by_day(db)
        assert len(result) == 1
        assert result[0]["total_cost_usd"] == pytest.approx(2.5)

    async def test_single_process_two_days_uses_deltas(self, db) -> None:
        # Day 1 reaches 3.0; Day 2 reaches 5.0 → daily deltas 3.0 and 2.0
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=3.0
        )
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY2_START + 60, cost_usd=5.0
        )
        result = await costs.costs_by_day(db)
        # Result is ordered DESC by day
        assert len(result) == 2
        assert result[0]["total_cost_usd"] == pytest.approx(2.0)
        assert result[1]["total_cost_usd"] == pytest.approx(3.0)

    async def test_multi_session_same_day_sums(self, db) -> None:
        # Two unrelated sessions on the same day, $2 + $3 = $5
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=2.0
        )
        await _seed_statusline(
            db, session_id="s2", pid=20, received_at=DAY1_START + 120, cost_usd=3.0
        )
        result = await costs.costs_by_day(db)
        assert len(result) == 1
        assert result[0]["total_cost_usd"] == pytest.approx(5.0)

    async def test_multi_process_same_session_same_day_sums(self, db) -> None:
        # Same session, two distinct pids on the same day; cost is per-pid
        # cumulative, so sum of MAX(cost) per pid.
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=4.0
        )
        await _seed_statusline(
            db, session_id="s1", pid=20, received_at=DAY1_START + 120, cost_usd=1.5
        )
        result = await costs.costs_by_day(db)
        assert len(result) == 1
        assert result[0]["total_cost_usd"] == pytest.approx(5.5)

    async def test_pid_reuse_with_death_yields_two_instances(self, db) -> None:
        # Instance 1: pid=10 reaches $7 then dies on day 1
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=7.0
        )
        await _seed_death(db, pid=10, observed_at=DAY1_START + 100)
        # Instance 2: same pid, fresh counter on day 2 reaches $4
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY2_START + 60, cost_usd=4.0
        )
        result = await costs.costs_by_day(db)
        # Without instance windowing, day2 would compute 4.0 - 7.0 = -3.0
        # With windowing, day1=$7 day2=$4
        by_day = {row["day"]: row["total_cost_usd"] for row in result}
        assert len(by_day) == 2
        days = sorted(by_day.keys())
        assert by_day[days[0]] == pytest.approx(7.0)
        assert by_day[days[1]] == pytest.approx(4.0)

    async def test_returns_descending_by_day(self, db) -> None:
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=1.0
        )
        await _seed_statusline(
            db, session_id="s2", pid=20, received_at=DAY3_START + 60, cost_usd=2.0
        )
        result = await costs.costs_by_day(db)
        days = [row["day"] for row in result]
        assert days == sorted(days, reverse=True)

