    async def test_pid_reuse_resets_token_counter(self, db) -> None:
        # Instance 1 reaches 100 input, dies. Instance 2 (same pid, same cwd,
        # new session in practice) starts fresh and reaches 60 on day 2.
        # Without instance windowing, day 2 would show 60 - 100 = -40.
        await _seed_statusline(
            db,
            session_id="s1",
            pid=10,
            received_at=DAY1_START + 60,
            cost_usd=1.0,
            input_tokens=100,
        )
        await _seed_death(db, pid=10, observed_at=DAY1_START + 100)
        await _seed_statusline(
            db,
            session_id="s1",
            pid=10,
            received_at=DAY2_START + 60,
            cost_usd=0.5,
            input_tokens=60,
        )
        result = await costs.costs_by_day(db)
        by_day = {row["day"]: row for row in result}
        days = sorted(by_day.keys())
        assert by_day[days[0]]["input_tokens"] == 100
        assert by_day[days[1]]["input_tokens"] == 60

